quest(url: components.url!)        request.httpMethod = "POST"        let (data, _) = try await URLSession.shared.data(for: request)        return try decoder.decode(T.self, from: data)    }    func put<Body: Encodable>(_ path: String, body: Body) async throws {        var request = URLRequest(url: baseUrl.appendingPathComponent(path))        request.httpMethod = "PUT"        request.setValue("application/json", forHTTPHeaderField: "Content-Type")        request.httpBody = try encoder.encode(body)        _ = try await URLSession.shared.data(for: request)    }    func delete(_ path: String) async throws {        var request = URLRequest(url: baseUrl.appendingPathComponent(path))        request.httpMethod = "DELETE"        _ = try await URLSession.shared.data(for: request)    }    }extension ApiClient {    func getAll() async throws -> [AccountDto] {        try await get("/accounts")    }}